const days = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado']; // mantido
const pad = (n) => String(n).padStart(2, '0');

const TZ = 'America/Sao_Paulo';

// Pega partes da data/hora já no fuso correto (independente do servidor)
function getParts(date) {
  const parts = new Intl.DateTimeFormat('pt-BR', {
    timeZone: TZ,
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    year: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(date);

  const obj = {};
  for (const p of parts) obj[p.type] = p.value;

  // pt-BR costuma vir "segunda-feira", a gente quer "segunda"
  const weekday = (obj.weekday || '').toLowerCase().replace('-feira', '').trim();

  return {
    weekday,
    day: obj.day,
    month: obj.month,
    year2: obj.year,
    hour: obj.hour,
    minute: obj.minute,
  };
}

const now = new Date();
const nowP = getParts(now);

let result = `Hoje é ${nowP.weekday} ${nowP.day}/${nowP.month}/${nowP.year2} às ${nowP.hour}:${nowP.minute}\n`;

for (let i = 1; i <= 6; i++) {
  const future = new Date(now);
  future.setDate(now.getDate() + i);

  const fP = getParts(future);

  let label = '';

  if (i === 1) {
    label = `Amanhã é ${fP.weekday} ${fP.day}/${fP.month}/${fP.year2}`;
  } else if (i === 2) {
    label = `Depois de amanhã é ${fP.weekday} ${fP.day}/${fP.month}/${fP.year2}`;
  } else {
    label = `A próxima ${fP.weekday} será dia ${fP.day}/${fP.month}/${fP.year2}`;
  }

  result += `${label}\n`;
}

return [
  {
    json: {
      resultado: result.trim(),
    },
  },
];
